# Unit Tests for `title_case`

```python
import pytest
from mymodule import title_case  # adjust import to your module


class TestTitleCaseHappyPath:
    """Tests for typical, expected inputs."""

    def test_single_lowercase_word(self):
        assert title_case("hello") == "Hello"

    def test_single_uppercase_word(self):
        assert title_case("HELLO") == "Hello"

    def test_two_words(self):
        assert title_case("hello world") == "Hello World"

    def test_multiple_words(self):
        assert title_case("the quick brown fox") == "The Quick Brown Fox"

    def test_already_title_cased(self):
        assert title_case("Hello World") == "Hello World"

    def test_mixed_case_input(self):
        assert title_case("hELLo WoRLd") == "Hello World"

    def test_words_with_numbers(self):
        assert title_case("hello world123") == "Hello World123"

    def test_words_starting_with_number(self):
        # capitalize() leaves leading digits as-is and lowercases the rest
        assert title_case("123abc 456def") == "123abc 456def"


class TestTitleCaseEdgeCases:
    """Tests for edge cases and unusual but valid inputs."""

    def test_empty_string(self):
        assert title_case("") == ""

    def test_single_space(self):
        assert title_case(" ") == ""

    def test_only_whitespace(self):
        assert title_case("    ") == ""

    def test_leading_whitespace(self):
        assert title_case("   hello") == "Hello"

    def test_trailing_whitespace(self):
        assert title_case("hello   ") == "Hello"

    def test_leading_and_trailing_whitespace(self):
        assert title_case("  hello world  ") == "Hello World"

    def test_multiple_spaces_between_words(self):
        # split() collapses consecutive whitespace
        assert title_case("hello    world") == "Hello World"

    def test_tabs_and_newlines_as_separators(self):
        assert title_case("hello\tworld\nfoo") == "Hello World Foo"

    def test_single_character(self):
        assert title_case("a") == "A"

    def test_single_character_uppercase(self):
        assert title_case("A") == "A"

    def test_word_with_apostrophe(self):
        # capitalize() lowercases everything after the first char
        assert title_case("don't stop") == "Don't Stop"

    def test_word_with_hyphen(self):
        # Hyphenated words are treated as single tokens by split()
        assert title_case("well-known fact") == "Well-known Fact"

    def test_punctuation_attached(self):
        assert title_case("hello, world!") == "Hello, World!"

    def test_unicode_characters(self):
        assert title_case("café münchen") == "Café München"

    def test_unicode_uppercase_input(self):
        assert title_case("CAFÉ MÜNCHEN") == "Café München"

    def test_emoji_in_string(self):
        # Emojis don't have a case; capitalize affects only following chars
        assert title_case("hello 🌍 world") == "Hello 🌍 World"

    def test_all_whitespace_types(self):
        assert title_case("\t\n  \r") == ""

    def test_long_string(self):
        words = ["word"] * 1000
        input_str = " ".join(words)
        expected = " ".join(["Word"] * 1000)
        assert title_case(input_str) == expected


class TestTitleCaseErrorCases:
    """Tests for invalid inputs that should raise exceptions."""

    def test_none_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            title_case(None)

    def test_integer_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            title_case(123)

    def test_list_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            title_case(["hello", "world"])

    def test_dict_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            title_case({"a": 1})

    def test_bytes_raises_type_error(self):
        # bytes.split() returns list[bytes]; ' '.join expects str
        with pytest.raises(TypeError):
            title_case(b"hello world")


@pytest.mark.parametrize("input_str,expected", [
    ("", ""),
    ("a", "A"),
    ("hello", "Hello"),
    ("hello world", "Hello World"),
    ("HELLO WORLD", "Hello World"),
    ("  spaced  out  ", "Spaced Out"),
    ("one", "One"),
    ("python is fun", "Python Is Fun"),
])
def test_title_case_parametrized(input_str, expected):
    assert title_case(input_str) == expected
```

## Notes on Test Coverage

- **Happy path:** Single/multiple words, varied capitalization, words with numbers.
- **Edge cases:** Empty strings, whitespace-only, mixed whitespace types (tabs, newlines), unicode, emojis, punctuation, hyphenated words. These document important quirks of `str.capitalize()` (e.g., `"well-known"` → `"Well-known"`, not `"Well-Known"`).
- **Error cases:** `None`, integers, lists, dicts (all raise `AttributeError` since they lack `.split()`), and `bytes` (raises `TypeError` due to mixing bytes and str in `join`).
- **Parametrized tests** provide a quick regression sweep over common inputs.

